import (
	context "context"
	fernclient "github.com/cli-multi-spec-namespaced/fern/client"
	option "github.com/cli-multi-spec-namespaced/fern/option"
	v2 "github.com/cli-multi-spec-namespaced/fern/v2"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.V2.ListUsers(
	context.TODO(),
	&v2.ListUsersRequest{},
)

